var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"왓슨 아멜리아는 그녀의 시청자, 티메이츠를 위해 직접 쓴 편지를 낭독하기로 했다.","JPN":"ワトソン・アメリアは彼女のリスナー、Teammatesのために自筆の手紙を朗読すると決めた。","ENG":"Watson Amelia decided to read a special letter that she has written for her loyal viewers, Teamates.","TWN":"Watson Amelia decided to read a special letter that she has written for her loyal viewers, Teamates."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"곧, 그녀가 무대 뒤에 도착했다는 무전이 들려왔다.","JPN":"先ほど、彼女がバックステージに着いたとの連絡があった。","ENG":"Soon, a radio call arrived saying that she has arrived backstage.","TWN":"Soon, a radio call arrived saying that she has arrived backstage."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HARIM_REBBIT_CLB_003","text":{"KOREA":"킁킁. 사건의 냄새가 나는군. 오, 의뢰서잖아! 뭐라고 적혀 있나 궁금한데!","JPN":"くんくん。事件の臭いがプンプンするね。お、依頼書が！　なんて書いているんだろ？","ENG":"Sniff sniff. I can sense a case over here. Oh, a request form! Wonder what it says!","TWN":"Sniff sniff. I can sense a case over here. Oh, a request form! Wonder what it says!"},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_CLB_003","face":"UNIT_PRIDE"},"R":null}},"voice":"clb003_lifetime_voice_501"},{"id":"L9_1","type":"dialog","speaker":"HARIM_REBBIT_CLB_003","text":{"KOREA":"내가 필요로 했을 때 나를 찾아주고 곁에 있어 줬던 모든 티메이츠에게.","JPN":"アタシが助けを必要としてた時に会いに来て、そばにいてくれたTeammatesへ。","ENG":"To all Teamates who found and comforted me in times of need.","TWN":"To all Teamates who found and comforted me in times of need."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_CLB_003","face":"UNIT_IDLE"},"R":null}},"voice":"clb003_lifetime_voice_502"},{"id":"L10_1","type":"dialog","speaker":"HARIM_REBBIT_CLB_003","text":{"KOREA":"오! 이건 편지잖아! 내 생각에는 이 편지를 읽는 게 이번 의뢰인 것 같아. 의뢰한 사람은… 왓슨 아멜리아네.","JPN":"おっと、これはアタシの手紙だね！　多分この手紙を読むのが今回の依頼なんじゃないかな。依頼主は……ワトソン・アメリア。","ENG":"Oh! It is a letter! I think this request is to read the letter with this request form. The requestor’s name is…… Amelia Watson.","TWN":"Oh! It is a letter! I think this request is to read the letter with this request form. The requestor’s name is…… Amelia Watson."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_CLB_003","face":"UNIT_LAUGH"},"R":null}},"voice":"clb003_lifetime_voice_503"},{"id":"L11_1","type":"dialog","speaker":"HARIM_REBBIT_CLB_003","text":{"KOREA":"에헴. 뭐라고 쓰여 있나 볼까.","JPN":"えっと、なんて書いてあるか見てみよう。","ENG":"Ahem. Wonder what it says.","TWN":"Ahem. Wonder what it says."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_CLB_003","face":"UNIT_PRIDE"},"R":null}},"voice":"clb003_lifetime_voice_504"},{"id":"L12_1","type":"dialog","speaker":"HARIM_REBBIT_CLB_003","text":{"KOREA":"나에게 열정을 쏟고 응원을 보내는 티메이츠에게 항상 감사하고 있어.","JPN":"アタシに夢中になってくれて、応援してくれるTeammatesにはいつも感謝しているよ。","ENG":"I am always grateful for all the passion and support the Teamates give me.","TWN":"I am always grateful for all the passion and support the Teamates give me."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_CLB_003","face":"UNIT_IDLE"},"R":null}},"voice":"clb003_lifetime_voice_505"},{"id":"L13_1","type":"dialog","speaker":"HARIM_REBBIT_CLB_003","text":{"KOREA":"네가 아니었다면, 이곳에서 잊지 못할 추억을 만들지도 못했을 거야.","JPN":"あなたじゃなかったら、ここでの忘れられない思い出なんてきっと作れなかっただろうね。","ENG":"If it wasn’t for you guys, I am sure I would not be here today making another unforgettable memory.","TWN":"If it wasn’t for you guys, I am sure I would not be here today making another unforgettable memory."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_CLB_003","face":"UNIT_IDLE"},"R":null}},"voice":"clb003_lifetime_voice_506"},{"id":"L14_1","type":"dialog","speaker":"HARIM_REBBIT_CLB_003","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_CLB_003","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HARIM_REBBIT_CLB_003","text":{"KOREA":"뭐? 너도 그렇다고? 아하하! 역시 네가 너무 좋아!","JPN":"え、あなたもそう思ってくれたの？　あはは！　アタシはやっぱあなたたちが大好きだよ！","ENG":"What? You guys are thanking me too? Ahahaha! Aww, I love you guys!","TWN":"What? You guys are thanking me too? Ahahaha! Aww, I love you guys!"},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_CLB_003","face":"UNIT_PRIDE"},"R":null}},"voice":"clb003_lifetime_voice_507"},{"id":"L16_1","type":"dialog","speaker":"HARIM_REBBIT_CLB_003","text":{"KOREA":"오, 하지만 아직 끝나지 않았어! 아직 모든 편지… 그러니까, 의뢰서의 내용을 다 읽지 못했거든.","JPN":"お、でもまだ終わりじゃないよ！　まだ手紙……だから、依頼書の内容を読み終えてないからね。","ENG":"Oh, but there’s more! I haven’t finished reading all the lett… I mean request form yet.","TWN":"Oh, but there’s more! I haven’t finished reading all the lett… I mean request form yet."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_CLB_003","face":"UNIT_LAUGH"},"R":null}},"voice":"clb003_lifetime_voice_508"},{"id":"L17_1","type":"dialog","speaker":"HARIM_REBBIT_CLB_003","text":{"KOREA":"내가 방송할 때마다 네 시간을 쪼개 방송을 보고 응원해 주고, 같이 즐겁게 보냈지. 나에겐 말로 표현할 수 없을 정도로 큰 의미로 다가와.","JPN":"アタシが配信する度にあなたは大切な時間を割いて見て、応援して、一緒に楽しい時間を過ごしてくれた。アタシにはそれが言葉にもできないくらい大切に思えてくるの。","ENG":"Whenever I stream, you guys spare your personal time to come to my channel to support me and have fun together. This means too much to me to describe it in words.","TWN":"Whenever I stream, you guys spare your personal time to come to my channel to support me and have fun together. This means too much to me to describe it in words."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_CLB_003","face":"UNIT_IDLE"},"R":null}},"voice":"clb003_lifetime_voice_509"},{"id":"L18_1","type":"dialog","speaker":"HARIM_REBBIT_CLB_003","text":{"KOREA":"모두 각자의 생활이 있는 만큼 시간을 낸다는 게 힘들다는 걸 알고 있단 말이야.","JPN":"だってみんなそれぞれの生活があるはずだから、時間を割くのがどれだけ大変なはずだから。","ENG":"It’s difficult to spare time when everyone is so busy with their own lives.","TWN":"It’s difficult to spare time when everyone is so busy with their own lives."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_CLB_003","face":"UNIT_DESPAIR"},"R":null}},"voice":"clb003_lifetime_voice_510"},{"id":"L19_1","type":"dialog","speaker":"HARIM_REBBIT_CLB_003","text":{"KOREA":"어떻게 아냐고? 글쎄, 나는 hololive EN 최고의 명탐정이니까!","JPN":"どうしてそれを知ってるかって？　まぁ、アタシはhololive EN随一の名探偵だからね！","ENG":"How do I know this? Well, I am the number one detective in hololive EN, of course!","TWN":"How do I know this? Well, I am the number one detective in hololive EN, of course!"},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_CLB_003","face":"UNIT_PRIDE"},"R":null}},"voice":"clb003_lifetime_voice_511"},{"id":"L20_1","type":"dialog","speaker":"HARIM_REBBIT_CLB_003","text":{"KOREA":"좋아, 의뢰서는 이제 던져 버리고.","JPN":"よし、依頼書はもういらないや。","ENG":"Right, throwing this form aside.","TWN":"Right, throwing this form aside."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_CLB_003","face":"UNIT_LAUGH"},"R":null}},"voice":"clb003_lifetime_voice_512"},{"id":"L21_1","type":"dialog","speaker":"HARIM_REBBIT_CLB_003","text":{"KOREA":"사실 다른 말은 필요 없어, 나에게 있어서 너는 둘도 없는 최고의 티메이츠야.","JPN":"実は他の言葉はいらないんだよね。アタシにとってあなたは掛け替えのない最高のTeammatesだよ。","ENG":"All I want to say is that you guys are the best Teamate I could have ever asked for.","TWN":"All I want to say is that you guys are the best Teamate I could have ever asked for."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_CLB_003","face":"UNIT_IDLE"},"R":null}},"voice":"clb003_lifetime_voice_513"}]`);export{e as default};